class Solution:
    def numberOfBoomerangs(self, points):
        # O(n^3) brute force: check all ordered triples
        count = 0
        n = len(points)
        for i in range(n):
            for j in range(n):
                if i == j:
                    continue
                for k in range(n):
                    if k == i or k == j:
                        continue
                    dij = (points[i][0]-points[j][0])**2 + (points[i][1]-points[j][1])**2
                    dik = (points[i][0]-points[k][0])**2 + (points[i][1]-points[k][1])**2
                    if dij == dik:
                        count += 1
        return count

