class Solution:
    def numberOfBoomerangs(self, points):
        from collections import defaultdict
        count = 0
        for i in points:
            dist_map = defaultdict(int)
            for j in points:
                if i is j:
                    continue
                d = (i[0]-j[0])**2 + (i[1]-j[1])**2
                dist_map[d] += 1
            for m in dist_map.values():
                count += m * (m - 1)
        return count

